function [ dataf ] = pf2_bpf_butter( data,filtOrder,fs,lowF,highF,restoreMean)% inputs ------------------------% data: data to be filtered% filtOrder: filter order% fs: sampling freq.% lowF: highpass cut-off frequency% highF: lowpass cutoff frequency% restoreMean: add back in 0 frequency data% outputs -----------------------% dataf: filtered data%--------------------------------% bpf function designs bandpass butterworth filter with the specified cut-off frequencies and order.% It filters the data columnwise as its output%--------------------------------if(nargin<6)   restoreMean=false; end[Mini,Nini]=size(data);if Mini==1 %if the data is a row vector converts it to column vector    data=data';end[M,N]=size(data);%-----------------------------------------------------------------% Band-pass Filter design%-----------------------------------------------------------------half_fs = fs/2;    %half of sampling freq. equal to pi[A,B,C,D] = butter(filtOrder,[lowF highF]/half_fs);minLen=filtOrder*3;if size(data,1)<=minLen    warning('Data length (%i) must be at least 3 * filter order',size(data,1));    dataf=nan(size(data));else    sos = ss2sos(A,B,C,D);        try        dataf=filtfilt(sos,1,data);        catch        dataf=nantolerant_filtfilt(sos,1,data);    end    if(restoreMean)       dataf=dataf+nanmean(data,1);     end    if Mini==1 %if the data is a row vector converts it to column vector        dataf=dataf';    endendendfunction dataf=nantolerant_filtfilt(b,a,data)    datamask=isnan(data)|isinf(data);        data(datamask)=nanmedian(data(:));    for i=1:size(data,2)       data(datamask(:,i),i)=nanmedian(data(:,i));     end    data(isnan(data))=0;        dataf=filtfilt(b,a,data);        dataf(datamask)=nan;end